#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int c,n,m,f[N][17],dep[N],g[2010][2010],h[N];
vector<int> e[N],s[N];
vector<pair<int,int>> vp;

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(int v:e[x])
        if(v!=fa){
            f[v][0]=x;
            for(int i=1;i<17;i++)
                f[v][i]=f[f[v][i-1]][i-1];
            dfs(v,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

int dis(int x,int y){
    return dep[x]+dep[y]-2*dep[LCA(x,y)]+1;
}

bool cmp(int,int);

void cal(int x,int y){
    if(~g[x][y])
        return;
    vp.push_back(make_pair(x,y));
    if(h[x]!=h[y]){
        g[x][y]=(h[x]>h[y]);
        g[y][x]=(h[y]>h[x]);
        return;
    }
    sort(s[x].begin(),s[x].end(),cmp);
    sort(s[y].begin(),s[y].end(),cmp);
    for(int i=0;i<min(s[x].size(),s[y].size());i++){
        int u=s[x][i],v=s[y][i];
        cal(u,v);
        if(g[u][v]){
            g[x][y]=1;
            g[y][x]=0;
            return;
        }
        if(g[v][u]){
            g[x][y]=0;
            g[y][x]=1;
            return;
        }
    }
    if(s[x].size()>s[y].size()){
        g[x][y]=1;
        g[y][x]=0;
    }else if(s[x].size()<s[y].size()){
        g[x][y]=0;
        g[y][x]=1;
    }else
        g[x][y]=g[y][x]=0;
}

bool cmp(int x,int y){
    cal(x,y);
    return g[x][y];
}

void dfs2(int x,int fa){
    s[x].clear();
    h[x]=1;
    for(int y:e[x])
        if(y!=fa){
            dfs2(y,x);
            h[x]=max(h[x],h[y]+1);
            s[x].push_back(y);
        }
}

int main(){
    scanf("%d",&c);
    scanf("%d",&n);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    scanf("%d",&m);
    if(c==1){
        int rt=1;
        for(int i=1;i<=n;i++)
            if(e[i].size()>1){
                rt=i;
                break;
            }
        while(m--){
            int s,t,ox,oy,r,res=0;
            scanf("%d%d%d%d%d",&s,&t,&ox,&oy,&r);
            vector<int> vx,vy;
            vx.clear(),vy.clear();
            vx.push_back(s);
            if(ox && s!=t){
                vx.push_back(t);
                if(s!=rt && t!=rt)
                    vx.push_back(rt);
            }
            vy.push_back(t);
            if(oy && s!=t){
                vy.push_back(s);
                if(s!=rt && t!=rt)
                    vy.push_back(rt);
            }
            for(int i:vx)
                for(int j:vy)
                    if(i==j) res++;
                    else if(r>1) res+=(i==rt || j==rt || r>2);
            //printf("%d %d %d %d %d %d %d\n",s,t,ox,oy,r,vx.size(),vy.size());
            printf("%d\n",res);
        }
    }else if(c==2){
        dfs(1,0);
        while(m--){
            int s,t,ox,oy,r;
            scanf("%d%d%d%d%d",&s,&t,&ox,&oy,&r);
            if(ox && oy)
                printf("%d\n",dis(s,t));
            else if(ox || oy || s==t)
                printf("1\n");
            else
                printf("0\n");
        }
    }else{
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                g[i][j]=-1*(i!=j);
        while(m--){
            int s,t,ox,oy,r;
            scanf("%d%d%d%d%d",&s,&t,&ox,&oy,&r);
            dfs2(s,0);
            int sum=0;
            for(int i=1;i<=n;i++){
                cal(i,t);
                if(g[i][t])
                    sum++;
            }
            if(sum+1<=r)
                puts("1");
            else
                puts("0");
            for(pair<int,int> i:vp)
                g[i.first][i.second]=g[i.second][i.first]=-1;
            vp.clear();
        }
    }
    return 0;
}
